import React, { useState } from 'react';
import axios from 'axios';

function ReviewForm({ bookId, onReviewAdded, api_url }) {
  const [name, setName] = useState('');
  const [rating, setRating] = useState(5);
  const [comment, setComment] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      const newReview = { name, rating: parseInt(rating), comment };
      const response = await axios.post(`${api_url}/books/${bookId}/reviews`, newReview);
      onReviewAdded(response.data);
      // Clear form
      setName('');
      setRating(5);
      setComment('');
    } catch (error) {
      console.error('Error adding review:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    <div className="mt-8 bg-blue-50 rounded-xl p-8 shadow-inner">
      <h3 className="text-2xl font-bold text-gray-800 mb-4">Add a Review</h3>
      <form onSubmit={handleSubmit} className="space-y-4">
        <div>
          <label htmlFor="name" className="block text-gray-700 font-semibold mb-1">Your Name</label>
          <input
            type="text"
            id="name"
            value={name}
            onChange={(e) => setName(e.target.value)}
            required
            className="w-full p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <div>
          <label htmlFor="rating" className="block text-gray-700 font-semibold mb-1">Rating</label>
          <select
            id="rating"
            value={rating}
            onChange={(e) => setRating(e.target.value)}
            className="w-full p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          >
            {[1, 2, 3, 4, 5].map(star => (
              <option key={star} value={star}>{star} Star{star > 1 && 's'}</option>
            ))}
          </select>
        </div>
        <div>
          <label htmlFor="comment" className="block text-gray-700 font-semibold mb-1">Comment</label>
          <textarea
            id="comment"
            value={comment}
            onChange={(e) => setComment(e.target.value)}
            rows="4"
            required
            className="w-full p-3 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500"
          />
        </div>
        <button
          type="submit"
          disabled={isSubmitting}
          className="w-full bg-blue-600 text-white font-bold py-3 px-6 rounded-lg shadow-md hover:bg-blue-700 transition-colors duration-300 transform hover:scale-105 disabled:bg-gray-400 disabled:scale-100"
        >
          {isSubmitting ? 'Submitting...' : 'Submit Review'}
        </button>
      </form>
    </div>
  );
}

export default ReviewForm;
